const globals = $('02. Stats globales').first().json;
const categories = $('03. Stats par categorie').all().map(i => i.json);
const complexity = $('04. Stats par complexite').all().map(i => i.json);
const topAutomations = $('05. Top automatisations').all().map(i => i.json);
const topClients = $('06. Top clients').all().map(i => i.json);

const nbCatalogue = Number(globals.nb_catalogue) || 0;
const nbActives = Number(globals.nb_actives) || 0;
const tauxAdoption = nbCatalogue > 0 ? Math.round((nbActives / nbCatalogue) * 100) : 0;

return [{ json: {
  success: true,
  data: {
    dashboard: {
      revenus: {
        mensuel: Number(globals.revenu_mensuel) || 0,
        setupTotal: Number(globals.revenu_setup_total) || 0,
        potentielMensuel: Number(globals.revenu_potentiel_mensuel) || 0,
        potentielSetup: Number(globals.revenu_potentiel_setup) || 0
      },
      compteurs: {
        catalogue: nbCatalogue,
        actives: nbActives,
        enAttente: Number(globals.nb_en_attente) || 0,
        suspendues: Number(globals.nb_suspendues) || 0,
        annulees: Number(globals.nb_annulees) || 0,
        totalAchats: Number(globals.nb_total_achats) || 0,
        clientsActifs: Number(globals.nb_clients_actifs) || 0,
        clientsTotal: Number(globals.nb_clients_total) || 0,
        tauxAdoption
      },
      parCategorie: categories,
      parComplexite: complexity,
      topAutomations,
      topClients
    }
  }
} }];
